module RefModule (
    input wire clk,
    input wire rst,
    input wire enable,
    output reg out
);
    reg [23:0] unused_counter;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            unused_counter <= 0;
            out <= 0;
        end else if (enable) begin
            if (unused_counter == 24'd12499999) begin // Adjust this value for frequency
                out <= ~out;
                unused_counter <= 0;
            end else begin
                unused_counter <= unused_counter + 1;
            end
        end else begin
            out <= 0; // Disable output when not enabled
        end
    end
endmodule
